    const unwatch = watch(infiniteLoader, (vm: any) => {
      // prints undefined
      console.log(vm.stateChanger);
      if (!vm) return
      emit('infinite', vm.stateChanger)
      unwatch()
    })

    return {
      infiniteLoader,
    }
  }
```

